def zip_dicts(*dicts):
    """Reference implementation – kept here so the file can be run standalone."""
    keys = set().union(*dicts)
    return {k: [d.get(k) for d in dicts] for k in keys}


# -------------------------- Happy path -------------------------- #

def test_zip_dicts_no_input():
    """Calling zip_dicts with no arguments should return an empty dict."""
    assert zip_dicts() == {}


def test_zip_dicts_single_dict():
    """A single dictionary should be zipped into lists of length 1."""
    d = {"a": 1, "b": 2}
    result = zip_dicts(d)
    assert result == {"a": [1], "b": [2]}


def test_zip_dicts_multiple_dicts_no_overlap():
    """When dictionaries have disjoint keys, each key gets a list with one
    actual value and None for the other positions."""
    d1 = {"x": 1, "y": 2}
    d2 = {"a": 10, "b": 20}
    result = zip_dicts(d1, d2)
    expected = {
        "x": [1, None],
        "y": [2, None],
        "a": [None, 10],
        "b": [None, 20],
    }
    assert result == expected


def test_zip_dicts_multiple_dicts_with_overlap():
    """Overlapping keys should collect values from each dict in order."""
    d1 = {"a": 1, "b": 2, "c": 3}
    d2 = {"b": 20, "c": 30, "d": 40}
    d3 = {"a": 100, "d": 400, "e": 500}
    result = zip_dicts(d1, d2, d3)
    expected = {
        "a": [1, None, 100],
        "b": [2, 20, None],
        "c": [3, 30, None],
        "d": [None, 40, 400],
        "e": [None, None, 500],
    }
    assert result == expected


def test_zip_dicts_preserves_none_values():
    """If a dict explicitly stores None, it should appear in the list."""
    d1 = {"a": None, "b": 1}
    d2 = {"a": 2, "b": None}
    result = zip_dicts(d1, d2)
    assert result == {"a": [None, 2], "b": [1, None]}


